import{_ as t,o as a,c as o,a3 as d}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Entitlements model","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Entitlements model | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/entitlements"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Entitlements model | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/entitlements"}]]},"headers":[],"relativePath":"developer-guide/entitlements.md","filePath":"developer-guide/entitlements.md","lastUpdated":1784157157000}'),s={name:"developer-guide/entitlements.md"};function n(l,e,i,r,c,p){return a(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="entitlements-model" tabindex="-1">Entitlements model <a class="header-anchor" href="#entitlements-model" aria-label="Permalink to &quot;Entitlements model&quot;">​</a></h1><p>How to <strong>build</strong> a licensed module end-to-end: <a href="/developer-guide/module-development">Module Development Standard</a>. Platform freeze: <a href="/getting-started/platform-freeze">platform-freeze.md</a>.</p><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><p>The platform does <strong>not</strong> sell plans or features. Licensing is based entirely on <strong>workspace module subscriptions</strong>.</p><p><strong>Licensing and authorization are separate concerns.</strong></p><table tabindex="0"><thead><tr><th>Layer</th><th>Concern</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td>Core Platform</td><td>Always-on</td><td>Platform capabilities (not modules, not billed)</td><td>Auth, users, roles, dashboard, billing, marketplace shell</td></tr><tr><td>Module</td><td>Licensing</td><td>Independently installable business domain</td><td>Leads, Tasks</td></tr><tr><td>Spatie Permission</td><td>Authorization</td><td>User access within an installed module</td><td><code>leads.view</code>, <code>tasks.create</code></td></tr><tr><td>Workspace module subscription</td><td>License row</td><td>Links a workspace to a module</td><td>Acme → Leads (<code>source=included</code>)</td></tr></tbody></table><p>There are <strong>no</strong> plan tiers, plan modules, plan features, feature catalogs, or module usage limits (e.g. “100 leads”).</p><p>A purchased or included module makes a business domain <strong>available</strong> to the workspace. It does <strong>not</strong> grant every user access. Admins assign Spatie roles and permissions to control who can use that domain.</p><h2 id="core-platform-vs-modules" tabindex="-1">Core Platform vs modules <a class="header-anchor" href="#core-platform-vs-modules" aria-label="Permalink to &quot;Core Platform vs modules&quot;">​</a></h2><p>Core Platform capabilities live in <code>config/core-platform.php</code> and are always available.</p><p>Business modules live in the <code>modules</code> catalog. Today only <strong>Leads</strong> and <strong>Tasks</strong> exist. They are:</p><ul><li><code>is_default_included = true</code></li><li><code>is_billable = false</code></li><li>Auto-installed on every new workspace (<code>source=included</code>)</li><li>Not cancellable by workspace owners (platform admin may <strong>deactivate</strong>)</li></ul><p>Schema remains flexible so they can become paid for <em>new</em> customers later without redesign (<code>is_billable</code>, pricing columns, <code>source</code>).</p><h2 id="resolution" tabindex="-1">Resolution <a class="header-anchor" href="#resolution" aria-label="Permalink to &quot;Resolution&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>active_modules(workspace) =</span></span>
<span class="line"><span>  workspace_module_subscriptions</span></span>
<span class="line"><span>    WHERE status IN (trial, active)</span></span>
<span class="line"><span>    AND (ends_at IS NULL OR ends_at &gt; now)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>has_module(workspace, slug) =</span></span>
<span class="line"><span>  module with that slug is in active_modules AND module.is_active</span></span>
<span class="line"><span></span></span>
<span class="line"><span>core = config(&#39;core-platform.capabilities&#39;)</span></span></code></pre></div><p>Cached as <code>workspace:{id}:entitlements</code> (1 hour). Invalidated on install/cancel/deactivate/status change.</p><p>API: <code>GET /api/central/v1/tenants/{tenant}/entitlements</code></p><p>Returns <code>{ core, modules }</code> for the tenant application to register licensed domains. User permissions come from Spatie Roles &amp; Permissions, not from this payload.</p><h2 id="routing-licensing-authorization" tabindex="-1">Routing (licensing + authorization) <a class="header-anchor" href="#routing-licensing-authorization" aria-label="Permalink to &quot;Routing (licensing + authorization)&quot;">​</a></h2><p>Tenant routes should pair middleware:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Route::middleware([&#39;auth:tenant-api&#39;, &#39;module:leads&#39;, &#39;can:leads.view&#39;])-&gt;group(...)</span></span></code></pre></div><ol><li><code>module:{slug}</code> — workspace owns/has the licensed module (<code>EnsureModule</code>)</li><li><code>can:{permission}</code> — authenticated user has the Spatie permission</li></ol><p>Only then allow access.</p><h2 id="marketplace-install-rules" tabindex="-1">Marketplace install rules <a class="header-anchor" href="#marketplace-install-rules" aria-label="Permalink to &quot;Marketplace install rules&quot;">​</a></h2><p>Published catalog: <code>GET /marketplace/modules</code> (admin browse) or install via <code>POST /tenants/{tenant}/modules</code>.</p><table tabindex="0"><thead><tr><th>Rule</th><th>Behavior</th></tr></thead><tbody><tr><td>Module must be <code>published</code> and <code>is_active</code></td><td>Validation error otherwise</td></tr><tr><td>Duplicate active/pending/trial install</td><td>Rejected</td></tr><tr><td>Required dependencies (<code>module_dependencies</code>, <code>is_optional=false</code>)</td><td>Must already be installed; marketplace detail returns <code>missing_required_modules</code></td></tr><tr><td>Non-billable module</td><td><code>status=active</code> immediately, <code>source=included</code> if <code>is_default_included</code> else <code>purchased</code></td></tr><tr><td>Billable module (<code>is_billable</code> + price &gt; 0)</td><td><code>status=pending</code> until Billing Engine settles payment</td></tr></tbody></table><p>Install body: <code>{ &quot;module_id&quot;: int, &quot;billing_cycle?&quot;: &quot;monthly&quot; | &quot;yearly&quot; }</code>.</p><h2 id="cancel-deactivate-rules" tabindex="-1">Cancel / deactivate rules <a class="header-anchor" href="#cancel-deactivate-rules" aria-label="Permalink to &quot;Cancel / deactivate rules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Who</th><th>Included modules</th><th>Purchased modules</th></tr></thead><tbody><tr><td><strong>Cancel</strong> (<code>POST /module-subscriptions/{id}/cancel</code>)</td><td>Requires <code>module-subscriptions.update</code></td><td><strong>Blocked</strong> — use deactivate</td><td>Sets <code>cancelled</code>, <code>ends_at=now</code></td></tr><tr><td><strong>Deactivate</strong> (<code>POST /module-subscriptions/{id}/deactivate</code>)</td><td>Requires <code>module-subscriptions.deactivate</code></td><td>Allowed (platform admin)</td><td>Sets <code>suspended</code></td></tr></tbody></table><p>Cancel removes entitlements immediately. Deactivate is the platform-admin override for included core modules.</p><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><p><code>module_dependencies</code> supports hard/optional deps for marketplace modules. Leads and Tasks have none today. <code>MarketplaceService::detailForTenant</code> exposes <code>required_modules</code>, <code>optional_modules</code>, <code>missing_required_modules</code>, <code>already_installed</code>.</p><h2 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h2><p>Each workspace has a consolidated billing profile (<code>billing_anchor_day</code>, <code>billing_cycle</code>, <code>proration_mode</code>, <code>next_billing_at</code>). One invoice per cycle for all <strong>billable active</strong> modules via <code>billing:run-consolidated</code>. Mid-cycle installs use proration modes: <code>prorated</code> | <code>free_until_next</code> | <code>none</code>. See <a href="/developer-guide/billing-engine">billing/billing-engine.md</a>.</p>`,34)])])}const h=t(s,[["render",n]]);export{m as __pageData,h as default};
